<template><div class="page-container" v-loading="loading"><section v-if="data.character" class="profile-detail"><div class="profile-portrait"><img v-if="data.character.avatarUrl" :src="data.character.avatarUrl"><div v-else class="avatar-placeholder large">{{ data.character.name?.[0] }}</div></div><div><p class="eyebrow">CHARACTER PROFILE</p><h1>{{ data.character.name }}</h1><el-tag>{{ data.character.gender||'未设置' }}</el-tag><p class="lead">{{ data.character.description||'暂无角色介绍。' }}</p></div></section><section class="section compact"><PageHeader title="出场作品"/><div class="simple-list"><router-link v-for="w in data.works||[]" :key="w.workId||w.id" :to="`/works/${w.workId||w.id}`">{{ w.workTitle||w.title||`作品 ${w.workId}` }}<span>{{ w.roleType||'' }}</span></router-link><EmptyState v-if="!data.works?.length"/></div></section><section class="section compact"><PageHeader title="角色关系"/><div class="relation-grid"><div v-for="r in data.relations||[]" :key="r.id" class="relation-card"><strong>{{ r.sourceName||r.sourceId }}</strong><span>{{ r.relationType }}</span><strong>{{ r.targetName||r.targetId }}</strong></div><EmptyState v-if="!data.relations?.length"/></div></section></div></template>
<script setup>import { onMounted,reactive,ref } from 'vue';import { useRoute } from 'vue-router';import PageHeader from '../../components/PageHeader.vue';import EmptyState from '../../components/EmptyState.vue';import { characterApi } from '../../api/character';const route=useRoute(),loading=ref(true),data=reactive({character:null,works:[],relations:[]});onMounted(async()=>{Object.assign(data,await characterApi.detail(route.params.id));loading.value=false})</script>
